mutation newApproval($request: ApprovalRequest!, $adminCertified: Boolean) {
  approval: submitRequest(request: $request, adminCertified: $adminCertified) {
    id
    type
    submittedTime
    modifiedTime
    status
    title
    providerName
    templateTitle
    amount
    version
    attachmentsCount
    submitter {
      id
      displayName
      __typename
    }
    observers {
      id
      type
      displayName
      __typename
    }
    history {
      actor {
        type
        id
        displayName
        ... on User {
          avatarKey
          __typename
        }
        __typename
      }
      status
      time
      __typename
    }
    fields {
      data
      name
      type
      key
      ... on HeaderField {
        fields {
          data
          name
          type
          key
          ... on HeaderField {
            fields {
              data
              name
              type
              key
              __typename
            }
            __typename
          }
          __typename
        }
        __typename
      }
      ... on ItemListField {
        fields {
          data
          name
          type
          key
          ... on HeaderField {
            fields {
              data
              name
              type
              key
              ... on HeaderField {
                fields {
                  data
                  name
                  type
                  key
                  __typename
                }
                __typename
              }
              __typename
            }
            __typename
          }
          __typename
        }
        __typename
      }
      ... on NumberField {
        value
        __typename
      }
      ... on CurrencyField {
        number: value
        currency
        __typename
      }
      ... on DateField {
        date: value
        __typename
      }
      ... on DataSetAttachmentField {
        dataSet: value {
          id
          name
          description
          owner {
            id
            displayName
            __typename
          }
          provider
          cardCount
          __typename
        }
        __typename
      }
      __typename
    }
    pendingApprover: pendingApproverEx {
      id
      type
      displayName
      ... on User {
        title
        avatarKey
        isCurrentUser
        __typename
      }
      ... on Group {
        userCount
        isDeleted
        currentUserIsMember
        __typename
      }
      __typename
    }
    chain {
      actor {
        displayName
        __typename
      }
      approver {
        id
        type
        displayName
        ... on User {
          title
          avatarKey
          isCurrentUser
          __typename
        }
        ... on Group {
          userCount
          isDeleted
          __typename
        }
        __typename
      }
      status
      time
      type
      key
      __typename
    }
    __typename
  }
}

